// ──────────────────────────────────────────────
// EXTRACT & VALIDATE WAHA/WhatsApp message
// Supports both WAHA format and Facebook Graph API
// ──────────────────────────────────────────────
const raw = $input.first().json;
const body = raw.body || raw;

let customerPhone, customerName, messageText, messageId;

// WAHA format
if (body.event === 'message' && body.payload) {
  customerPhone = body.payload.from?.replace('@c.us', '') || body.payload.from;
  customerName = body.payload.notifyName || body.payload.pushName || 'Customer';
  messageText = body.payload.body || body.payload.text || '';
  messageId = body.payload.id || Date.now().toString();
}
// Facebook Graph API format (legacy)
else if (body.entry?.[0]?.changes?.[0]?.value?.messages?.[0]) {
  const msg = body.entry[0].changes[0].value.messages[0];
  customerPhone = msg.from;
  customerName = body.entry[0].changes[0].value.contacts?.[0]?.profile?.name || 'Customer';
  messageText = msg.text?.body || msg.body || '';
  messageId = msg.id || Date.now().toString();
}
// Direct format (testing)
else {
  customerPhone = body.phone || body.from || 'unknown';
  customerName = body.name || 'Customer';
  messageText = body.message || body.text || '';
  messageId = body.id || Date.now().toString();
}

if (!messageText || messageText.trim() === '') {
  throw new Error('Empty message — skipping');
}

return [{
  json: {
    customerPhone,
    customerName,
    messageText: messageText.trim(),
    messageId,
    sessionId: `wa_${customerPhone}`,
    receivedAt: new Date().toISOString()
  }
}];

// ──────────────────────────────────────────────
// BUILD AGENTIC CONTEXT: History + Lead Profile
// ──────────────────────────────────────────────
const message = $node['Extract Message'].json;
const historyRaw = $node['Load Chat History'].json;
const leadRaw = $node['Lookup Lead Profile'].json;

// Build conversation history for memory
let history = [];
if (Array.isArray(historyRaw)) {
  history = historyRaw.reverse().map(h => ({
    role: h.direction === 'inbound' ? 'user' : 'assistant',
    content: h.message_text
  }));
}

// Build lead context
let leadContext = 'No existing lead profile found — this may be a new customer.';
const lead = Array.isArray(leadRaw) ? leadRaw[0] : leadRaw;
if (lead && lead.id) {
  leadContext = [
    `Existing Lead: ${lead.name}`,
    `Status: ${lead.status} | Priority: ${lead.ai_priority || 'unknown'}`,
    `Vehicle Interest: ${lead.vehicle_interest || 'Not specified'}`,
    `Budget: ${lead.budget_min ? 'AED ' + lead.budget_min + '-' + lead.budget_max : 'Unknown'}`,
    `Score: ${lead.ai_score || 'Not scored'}`
  ].join('\n');
}

return [{
  json: {
    ...message,
    chatHistory: history,
    leadContext,
    existingLeadId: lead?.id || null,
    isNewCustomer: !lead?.id
  }
}];

// ──────────────────────────────────────────────
// PARSE AI REPLY + DETECT ESCALATION
// ──────────────────────────────────────────────
const aiResponse = $input.first().json;
const context = $node['Build Agent Context'].json;

let aiReply;
try {
  aiReply = aiResponse.choices[0].message.content.trim();
} catch (e) {
  aiReply = 'Thank you for your message! Let me connect you with our team. A representative will reach out shortly. 🙏';
}

const needsEscalation = aiReply.includes('[ESCALATE]');
if (needsEscalation) {
  aiReply = aiReply.replace('[ESCALATE]', '').trim();
}

return [{
  json: {
    ...context,
    aiReply,
    needsEscalation,
    tokensUsed: aiResponse.usage?.total_tokens || 0
  }
}];

